    def _assert_windows_transactional_delete_barrier_failure(
        self,
        fixture,
        *,
        fsync_file_side_effect,
        expected_error_text,
    ):
        class DummyLock:
            def __init__(self, path, timeout_ms, retry_ms, debug):
                self.path = path

            def __enter__(self):
                return self

            def __exit__(self, exc_type, exc, tb):
                return False

